import React from "react"
import { IoCloseCircleSharp, IoHammerSharp } from 'react-icons/io5'

class User extends React.Component {
    render() {
        const { user } = this.props;  // Лучше использовать this.props

        return (
            <div className="user">
                <IoCloseCircleSharp onClick={() => this.props.on}className="delete-icon" />
                <IoHammerSharp className="edit-icon" />  {/* ← было classNmae, исправлено */}
                <h3>{user.firstname} {user.lastname}</h3>
                <p>{user.bio}</p>
                <b>{user.isHappy ? 'Хапи' : 'Бедни'}</b>
            </div>
        )
    }
}

export default User
